static Bitboard passed_pawn_mask(Color c, Square s) {
    File f = file_of(s);
    Rank r = rank_of(s);
    Bitboard mask = 0;
    Bitboard files = BB::FileBB[f] | adjacent_files(f);

    if (c == WHITE) {
        for (Rank rr = Rank(r + 1); rr <= RANK_7; rr = Rank(rr + 1))
            mask |= files & BB::RankBB[rr];
    } else {
        for (int rr = r - 1; rr >= RANK_2; --rr)
            mask |= files & BB::RankBB[rr];
    }
    return mask;
}

Piece piece_from_fen(char c) {
  switch (c) {
    case 'P':
      return Piece::WP;
    case 'N':
      return Piece::WN;
    case 'B':
      return Piece::WB;
    case 'R':
      return Piece::WR;
    case 'Q':
      return Piece::WQ;
    case 'K':
      return Piece::WK;
    case 'p':
