pub fn put_piece(&mut self, piece: Piece, sq: Square) {
    let bb = Bitboard::from_square(sq);
    self.pieces[piece.piece_type.index()] |= bb;
    self.colors[piece.color.index()] |= bb;
    self.mailbox[sq.index()] = Some(piece);
}

int Eval::evaluateForPhase(const Board &board, Color color) {
  int score = 0;

  Color otherColor = getOppositeColor(color);

  // Material value
  score += MATERIAL_VALUES[phase][PAWN]
      * (_popCount(board.getPieces(color, PAWN)) - _popCount(board.getPieces(otherColor, PAWN)));
  score += MATERIAL_VALUES[phase][KNIGHT]
      * (_popCount(board.getPieces(color, KNIGHT)) - _popCount(board.getPieces(otherColor, KNIGHT)));
  score += MATERIAL_VALUES[phase][BISHOP]
      * (_popCount(board.getPieces(color, BISHOP)) - _popCount(board.getPieces(otherColor, BISHOP)));
  score += MATERIAL_VALUES[phase][ROOK]
      * (_popCount(board.getPieces(color, ROOK)) - _popCount(board.getPieces(otherColor, ROOK)));
  score += MATERIAL_VALUES[phase][QUEEN]
      * (_popCount(board.getPieces(color, QUEEN)) - _popCount(board.getPieces(otherColor, QUEEN)));

  // Piece square tables
  score += board.getPSquareTable().getScore(phase, color) - board.getPSquareTable().getScore(phase, otherColor);

  // Mobility
  score += evaluateMobility(board, phase, color) - evaluateMobility(board, phase, otherColor);

  // Rook on open file
  score += ROOK_OPEN_FILE_BONUS[phase] * (rooksOnOpenFiles(board, color) - rooksOnOpenFiles(board, otherColor));

  // Bishop pair
  score += hasBishopPair(board, color) ? BISHOP_PAIR_BONUS[phase] : 0;
  score -= hasBishopPair(board, otherColor) ? BISHOP_PAIR_BONUS[phase] : 0;

  // Pawn structure
  score += evaluatePawnStructure(board, color, phase);

  // King pawn shield (not done in endgame so omit)
  if (phase == OPENING) {
    score +=
        KING_PAWN_SHIELD_BONUS[OPENING] * (pawnsShieldingKing(board, color) - pawnsShieldingKing(board, otherColor));
  }

  return score;
}

private int pieceSquareBonus(int pieceType, int square) {
    switch (pieceType) {
        case Piece.PAWN:
            return PAWN_PST[square];
        case Piece.KNIGHT:
            return KNIGHT_PST[square];
        case Piece.BISHOP:
            return BISHOP_PST[square];
        case Piece.ROOK:
            return ROOK_PST[square];
        case Piece.QUEEN:
            return QUEEN_PST[square];
        case Piece.KING:
            return KING_PST[square];
        default:
            return 0;
    }
}

public void putPiece(int piece, int sq) {
    long bit = Bitboard.bit(sq);
    pieces[piece] |= bit;
    int color = piece / 6;
    occupancy[color] |= bit;
    occupancy[2] |= bit;
    pieceAt[sq] = piece;
    zobristKey ^= Zobrist.PIECE_KEYS[piece][sq];
    int pieceType = piece % 6;
    if (pieceType == 0) {
        pawnKey ^= Zobrist.PIECE_KEYS[piece][sq];
    }
    phase += PHASE_VALUES[pieceType];
    // Incremental PST
    int pstSq = color == WHITE ? sq : sq ^ 56;
    pstScore[0] += com.chess.engine.eval.PieceSquareTables.MG_TABLE[pieceType][pstSq] * (color == WHITE ? 1 : -1);
    pstScore[1] += com.chess.engine.eval.PieceSquareTables.EG_TABLE[pieceType][pstSq] * (color == WHITE ? 1 : -1);
}

def _set_ep_square_if_capturable(self, ep_sq: int | None) -> None:
    """Set ep square only if the side to move can capture it (for repetition correctness)."""
    if ep_sq is None:
        self.ep_square = None
        return

    capturer = -self.turn  # after a double push, capturer is the opponent
    if capturer == WHITE:
        from1, from2 = ep_sq - 15, ep_sq - 17
        if (not _is_offboard(from1) and self.squares[from1] == WHITE * PAWN) or (
            not _is_offboard(from2) and self.squares[from2] == WHITE * PAWN
        ):
            self.ep_square = ep_sq
        else:
            self.ep_square = None
    else:
        from1, from2 = ep_sq + 15, ep_sq + 17
        if (not _is_offboard(from1) and self.squares[from1] == BLACK * PAWN) or (
            not _is_offboard(from2) and self.squares[from2] == BLACK * PAWN
        ):
            self.ep_square = ep_sq
        else:
            self.ep_square = None

def add_piece_eval(piece, pt, color, sq)
  mg_pst = PST::MG_TABLES[piece]
  eg_pst = PST::EG_TABLES[piece]
  mg_val = PST::MG_PIECE_VALUE[pt] + (mg_pst ? mg_pst[sq] : 0)
  eg_val = PST::EG_PIECE_VALUE[pt] + (eg_pst ? eg_pst[sq] : 0)

  if color == WHITE
    @mg_score += mg_val
    @eg_score += eg_val
    @w_bishops += 1 if pt == BISHOP
    @w_pawn_files[sq & 7] += 1 if pt == PAWN
  else
    @mg_score -= mg_val
    @eg_score -= eg_val
    @b_bishops += 1 if pt == BISHOP
    @b_pawn_files[sq & 7] += 1 if pt == PAWN
  end
  @phase += PST::PHASE_WEIGHTS[pt] || 0
end

def piece_value(piece)
  PIECE_VALUES.fetch(piece.downcase, 0)
end

