def _piece_square_delta(self, move: Move) -> int:
    frm, to, promo = move
    moving = int(self.board.tape[frm]) if 0 <= frm < 64 else 0
    moving_type = self._piece_type(moving)
    if moving_type == 0:
        return 0

    is_white = 1 <= moving <= 6

    def pst_idx(square: int) -> int:
        return (square ^ 56) if is_white else square

    from_idx = pst_idx(frm)
    to_idx = pst_idx(to)

    if promo:
        promoted_type = self._piece_type(promo)
        from_table = PST_BY_PIECE.get(1)
        to_table = PST_BY_PIECE.get(promoted_type)
        if from_table is not None and to_table is not None:
            return int(to_table[to_idx]) - int(from_table[from_idx])

    if moving_type == KING_TYPE:
        table = PST_KING_MID
    else:
        table = PST_BY_PIECE.get(moving_type)
        if table is None:
            return 0
    return int(table[to_idx]) - int(table[from_idx])
